/* ============================ SVG PIECES ============================ */

function Diya({ size = 46 }) {
  return (
    <span className="diya" style={{ width: size, height: size }}>
      <span className="flame" />
      <svg viewBox="0 0 60 40" width={size} height={size} aria-hidden="true">
        <defs>
          <linearGradient id="diyaG" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0" stopColor="#8a3d12" />
            <stop offset="1" stopColor="#c96a1e" />
          </linearGradient>
        </defs>
        <ellipse cx="30" cy="24" rx="24" ry="9" fill="url(#diyaG)" />
        <ellipse cx="30" cy="22" rx="20" ry="6.5" fill="#e5852b" />
        <ellipse cx="30" cy="21.5" rx="15" ry="4.5" fill="#f6c66b" />
        <path d="M6 24 q24 12 48 0" fill="none" stroke="#7a3410" strokeWidth="2" strokeLinecap="round" />
      </svg>
    </span>
  );
}

/* Kolam / rangoli — draws itself */
function Kolam({ size = 120, color = "var(--gold)" }) {
  return (
    <svg width={size} height={size} viewBox="0 0 120 120" aria-hidden="true" className="kolam">
      <g fill="none" stroke={color} strokeWidth="1.6" strokeLinecap="round">
        {Array.from({ length: 8 }).map((_, i) => (
          <g key={i} transform={`rotate(${i * 45} 60 60)`}>
            <path d="M60 60 q10 -22 0 -40 q-10 18 0 40" />
            <circle cx="60" cy="18" r="3" fill={color} stroke="none" />
          </g>
        ))}
        <circle cx="60" cy="60" r="10" />
        <circle cx="60" cy="60" r="4" fill={color} stroke="none" />
      </g>
    </svg>
  );
}

/* ============================ HOOKS ============================ */
function useReveal() {
  useEffect(() => {
    const els = document.querySelectorAll(".reveal");
    if (!("IntersectionObserver" in window)) {
      els.forEach((e) => e.classList.add("in"));
      return;
    }
    const io = new IntersectionObserver(
      (entries) => {
        entries.forEach((en) => {
          if (en.isIntersecting) {
            en.target.classList.add("in");
            io.unobserve(en.target);
          }
        });
      },
      { threshold: 0.18 }
    );
    els.forEach((e) => io.observe(e));
    return () => io.disconnect();
  }, []);
}

function useCountdown(targetISO) {
  const [t, setT] = useState({ d: 0, h: 0, m: 0, s: 0, done: false });
  useEffect(() => {
    const target = new Date(targetISO).getTime();
    const tick = () => {
      const diff = target - Date.now();
      if (diff <= 0) {
        setT({ d: 0, h: 0, m: 0, s: 0, done: true });
        return;
      }
      const d = Math.floor(diff / 86400000);
      const h = Math.floor((diff % 86400000) / 3600000);
      const m = Math.floor((diff % 3600000) / 60000);
      const s = Math.floor((diff % 60000) / 1000);
      setT({ d, h, m, s, done: false });
    };
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [targetISO]);
  return t;
}

